boardCommands.mermaid:
graph TD
    A[Start] --> B{Is instance null?};
    B -- Yes --> C[Acquire Lock & Initialize];
    B -- No --> D[Return existing instance];
    C --> E[End];
    D --> E;

graph LR
    A[Initial Access] --> B(Read from Main Memory); 
    B --> C[Store in Local Variable]; 
    C --> D{Subsequent Checks/Returns}; 
    D --> E[Use Local Variable];
